const express = require('express');
const router = express.Router();
const tasksService = require('./service');

router.get('/:projectId/tasks', (req, res) => {
  const { status } = req.query;
  const tasks = tasksService.getTasks(req.params.projectId, status);
  if (!tasks) return sendError(res, 404, 'NOT_FOUND', 'Tasks not found');
  res.json({ tasks });
});

router.patch('/:projectId/tasks/:taskId', (req, res) => {
  const { status } = req.body;
  if (!['todo', 'done'].includes(status)) return sendError(res, 400, 'BAD_REQUEST', 'Invalid task status');
  const updatedTask = tasksService.updateTaskStatus(req.params.projectId, req.params.taskId, status);
  if (!updatedTask) return sendError(res, 404, 'NOT_FOUND', 'Task not found');
  res.json({ task: updatedTask });
});

module.exports = router;

const projects = new Map();

export function addProject(name) {
  if (!name) return null;
  const id = randomUUID();
  projects.set(id, { id, name });
  return { id, name };
}

export function getProject(projectId) {
  return projects.get(projectId);
}

const tasks = new Map();

export function addTask(projectId, data) {
  const id = randomUUID();
  tasks.set(id, { projectId, ...data });
  return { id, ...data };
}

export function getTasks(projectId, status) {
  if (status && !['todo', 'done'].includes(status)) return null;
  const filteredTasks = Array.from(tasks.values()).filter(task => task.projectId === projectId);
  return status ? filteredTasks.filter(task => task.status === status) : filteredTasks;
}

export function updateTaskStatus(taskId, newStatus) {
  const task = tasks.get(taskId);
  if (!task) return null;
  task.status = newStatus;
  return { ...task };
}

